import { useRef } from "react";

import MainBtns from "../../Components/Buttons/MainBtns";
import InputForm from "../../Components/Input/InputForm";
import ListOnEdit from "../../Components/Lists/ListOnEdit";
import {NestedList} from "../../Components/Lists/NestedList";

function EditCoursePage() {

  const listRef = useRef();

  const handleSave = () => {
    if (listRef.current) {
      const data = listRef.current.getData(); // получаем объект root
      console.log("Сохраняем root:", data);
      localStorage.setItem("myList", JSON.stringify(data));
    }
  };
  return (
    <div>
      <div className="edit-course-box">

        <div className="left-panel-in-edit-course-page">
          <div>Предпросмотр</div>
          <div>Редактирование уроков</div>
        </div>
        <div className="main-edit">
          <div>
            <h2>Name and Price</h2>
            <InputForm zstyle={"mini-input"} TextPlaceholder={"Name of Course"}/>
            <InputForm zstyle={"mini-input"} TextPlaceholder={"Price ₺"}/>
          </div>

          <div>
            <ListOnEdit Name={"What Learn"}/>
          </div>
          <div style={{display:"flex", flexDirection:"column"}}>
            <h2>Description</h2>
            <textarea className="text-area"></textarea>
          </div>
          <div>
            <ListOnEdit Name={"Tags"}/>
          </div>
          <div>
            {/*<ListOnEdit Name={"Modules For Lesson"} NestedList={"true"} />*/}
            <NestedList/>
            <MainBtns Style={"purple-btn"} Text={"Сохранить"} Funct={handleSave}/>
          </div>
        </div>
      </div>
    </div>
  );
}

export default EditCoursePage;
